import{_ as n,c as r,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Änderungsprotokoll: Versionshistorie | opencode-md-table-formatter","description":"Erfahren Sie mehr über die Versionsentwicklung und neuen Funktionen von opencode-md-table-formatter. Sehen Sie sich die v0.1.0-Funktionen an, einschließlich automatischer Formatierung und Breitencaching.","frontmatter":{"title":"Änderungsprotokoll: Versionshistorie | opencode-md-table-formatter","sidebarTitle":"Versionsübersicht","subtitle":"Änderungsprotokoll: Versionshistorie und Änderungsaufzeichnungen","description":"Erfahren Sie mehr über die Versionsentwicklung und neuen Funktionen von opencode-md-table-formatter. Sehen Sie sich die v0.1.0-Funktionen an, einschließlich automatischer Formatierung und Breitencaching.","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"de/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"de/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),o={name:"de/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function l(s,e,a,u,g,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="anderungsprotokoll-versionshistorie-und-anderungsaufzeichnungen" tabindex="-1">Änderungsprotokoll: Versionshistorie und Änderungsaufzeichnungen <a class="header-anchor" href="#anderungsprotokoll-versionshistorie-und-anderungsaufzeichnungen" aria-label="Permalink to &quot;Änderungsprotokoll: Versionshistorie und Änderungsaufzeichnungen&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Was Sie lernen können</p><ul><li>Die Versionsentwicklung des Plugins verfolgen</li><li>Neue Funktionen und Fixes jeder Version verstehen</li><li>Bekannte Einschränkungen und technische Details beherrschen</li><li>Mögliche zukünftige Funktionsverbesserungen kennenlernen</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="neue-funktionen" tabindex="-1">Neue Funktionen <a class="header-anchor" href="#neue-funktionen" aria-label="Permalink to &quot;Neue Funktionen&quot;">​</a></h3><p>Dies ist die <strong>ursprüngliche Veröffentlichung</strong> von opencode-md-table-formatter mit den folgenden Kernfunktionen:</p><ul><li><strong>Automatische Tabellenformatierung</strong>: Automatische Formatierung von AI-generierten Markdown-Tabellen über den <code>experimental.text.complete</code>-Hook</li><li><strong>Unterstützung für versteckten Modus</strong>: Korrekte Behandlung versteckter Markdown-Symbole (wie <code>**</code>, <code>*</code>) bei der Breitenberechnung</li><li><strong>Verschachtelte Markdown-Verarbeitung</strong>: Unterstützung für Markdown-Syntax beliebiger Verschachtelungstiefe mit einem Multi-Pass-Stripping-Algorithmus</li><li><strong>Codeblock-Schutz</strong>: Markdown-Symbole in Inline-Code (<code>`code`</code>) bleiben wörtlich und nehmen nicht an der Breitenberechnung teil</li><li><strong>Ausrichtungsunterstützung</strong>: Unterstützung für Linksbündigkeit (<code>---</code> oder <code>:---</code>), Zentrierung (<code>:---:</code>) und Rechtsbündigkeit (<code>---:</code>)</li><li><strong>Breitencaching-Optimierung</strong>: Caching der berechneten Zeichenfolgenanzeigebreite zur Leistungssteigerung</li><li><strong>Validierung ungültiger Tabellen</strong>: Automatische Validierung der Tabellenstruktur, ungültige Tabellen erhalten einen Fehlerkommentar</li><li><strong>Unterstützung für mehrere Zeichen</strong>: Unterstützung für Emojis, Unicode-Zeichen, leere Zellen und überlange Inhalte</li><li><strong>Stille Fehlerbehandlung</strong>: Formatierungsfehler unterbrechen nicht den OpenCode-Workflow</li></ul><h3 id="technische-details" tabindex="-1">Technische Details <a class="header-anchor" href="#technische-details" aria-label="Permalink to &quot;Technische Details&quot;">​</a></h3><p>Diese Version enthält ca. <strong>230 Zeilen produktionsbereiten TypeScript-Code</strong>:</p><ul><li><strong>12 Funktionen</strong>: Klare Verantwortlichkeiten, gute Trennung</li><li><strong>Typsicherheit</strong>: Korrekte Verwendung des <code>Hooks</code>-Interfaces</li><li><strong>Intelligente Cache-Bereinigung</strong>: Ausgelöst bei mehr als 100 Operationen oder mehr als 1000 Cache-Einträgen</li><li><strong>Multi-Pass-Regex-Verarbeitung</strong>: Unterstützung für das Stripping von Markdown-Symbolen beliebiger Verschachtelungstiefe</li></ul><div class="tip custom-block"><p class="custom-block-title">Caching-Mechanismus</p><p>Der Cache ist zur Optimierung der Breitenberechnung für wiederholte Inhalte konzipiert. Wenn beispielsweise derselbe Zellentext mehrmals in einer Tabelle vorkommt, wird die Breite nur einmal berechnet und anschließend direkt aus dem Cache gelesen.</p></div><h3 id="bekannte-einschrankungen" tabindex="-1">Bekannte Einschränkungen <a class="header-anchor" href="#bekannte-einschrankungen" aria-label="Permalink to &quot;Bekannte Einschränkungen&quot;">​</a></h3><p>Diese Version unterstützt die folgenden Szenarien nicht:</p><ul><li><strong>HTML-Tabellen</strong>: Nur Markdown-Pipe-Tabellen werden unterstützt</li><li><strong>Mehrzeilige Zellen</strong>: Zellen mit <code>&lt;br&gt;</code>-Tags werden nicht unterstützt</li><li><strong>Tabellen ohne Trennzeile</strong>: Tabellen müssen eine Trennzeile (<code>|---|</code>) enthalten, um formatiert zu werden</li><li><strong>Anforderungen</strong>: Erfordert <code>@opencode-ai/plugin</code> &gt;= 0.13.7 (verwendet den nicht öffentlichen <code>experimental.text.complete</code>-Hook)</li></ul><div class="info custom-block"><p class="custom-block-title">Versionsanforderungen</p><p>Das Plugin benötigt OpenCode &gt;= 1.0.137 und <code>@opencode-ai/plugin</code> &gt;= 0.13.7, um ordnungsgemäß zu funktionieren.</p></div><hr><h2 id="zukunftige-plane" tabindex="-1">Zukünftige Pläne <a class="header-anchor" href="#zukunftige-plane" aria-label="Permalink to &quot;Zukünftige Pläne&quot;">​</a></h2><p>Die folgenden Funktionen sind für zukünftige Versionen geplant:</p><ul><li><strong>Konfigurationsoptionen</strong>: Unterstützung für benutzerdefinierte minimale/maximale Spaltenbreiten, Deaktivierung bestimmter Funktionen</li><li><strong>Unterstützung für Tabellen ohne Kopfzeile</strong>: Formatierung von Tabellen ohne Kopfzeile</li><li><strong>Leistungsoptimierung</strong>: Leistungsanalyse und Optimierung für sehr große Tabellen (100+ Zeilen)</li><li><strong>Weitere Ausrichtungsoptionen</strong>: Erweiterung der Syntax und Funktionen für Ausrichtungen</li></ul><div class="tip custom-block"><p class="custom-block-title">Mitwirken</p><p>Wenn Sie Funktionsvorschläge haben oder Code beitragen möchten, sind Ihre Ideen auf <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a> willkommen.</p></div><hr><h2 id="format-des-anderungsprotokolls" tabindex="-1">Format des Änderungsprotokolls <a class="header-anchor" href="#format-des-anderungsprotokolls" aria-label="Permalink to &quot;Format des Änderungsprotokolls&quot;">​</a></h2><p>Das Änderungsprotokoll dieses Projekts folgt dem <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>-Format, und die Versionsnummern folgen der <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>-Spezifikation.</p><p><strong>Format der Versionsnummer</strong>: <code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>: Inkompatible API-Änderungen</li><li><strong>MINOR</strong>: Rückwärtskompatible neue Funktionen</li><li><strong>PATCH</strong>: Rückwärtskompatible Fehlerbehebungen</li></ul><p><strong>Änderungstypen</strong>:</p><ul><li><strong>Added</strong>: Neue Funktionen</li><li><strong>Changed</strong>: Änderungen an bestehenden Funktionen</li><li><strong>Deprecated</strong>: Bald zu entfernende Funktionen</li><li><strong>Removed</strong>: Entfernte Funktionen</li><li><strong>Fixed</strong>: Fehlerbehebungen</li><li><strong>Security</strong>: Sicherheitsbezogene Fehlerbehebungen</li></ul><hr><h2 id="empfohlene-lesereihenfolge" tabindex="-1">Empfohlene Lesereihenfolge <a class="header-anchor" href="#empfohlene-lesereihenfolge" aria-label="Permalink to &quot;Empfohlene Lesereihenfolge&quot;">​</a></h2><p>Wenn Sie ein neuer Benutzer sind, empfehlen wir, in folgender Reihenfolge zu lernen:</p><ol><li><a href="./../../start/getting-started/">Schnellstart: Installation und Konfiguration</a> — Schneller Einstieg</li><li><a href="./../../start/features/">Funktionsübersicht: Die Magie der automatischen Formatierung</a> — Kernfunktionen verstehen</li><li><a href="./../../faq/troubleshooting/">Häufig gestellte Fragen: Was tun, wenn die Tabelle nicht formatiert wird</a> — Fehlerbehebung</li><li><a href="./../../appendix/limitations/">Bekannte Einschränkungen: Wo liegen die Grenzen des Plugins</a> — Einschränkungen verstehen</li></ol>',31)])])}const m=n(o,[["render",l]]);export{c as __pageData,m as default};
